(async function() {
  var images = "${images}";
  if (images && images.trim()) {
    var maxW = 30000, el = 0;
    while (el < maxW) {
      var c = document.querySelector('[data-testid="attachments"]');
      var btn = document.querySelector('[data-testid="tweetButton"]') || document.querySelector('[data-testid="tweetButtonInline"]');
